const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;

// Create a write stream for logging
const logStream = fs.createWriteStream(path.join(__dirname, 'access.log'), { flags: 'a' });

// Middleware to log requests
app.use(morgan(':date[iso] :remote-addr :method :url :status :res[content-length] - :response-time ms :user-agent :req[username] :req[custom-header]', { stream: logStream }));

// Middleware to parse JSON body
app.use(express.json());

// Route to accept user input
app.post('/log', (req, res) => {
    const { username, customHeader } = req.body;
    const ipAddress = req.ip;

    // Log user-provided data
    logStream.write(`User: ${username}, IP: ${ipAddress}, Custom Header: ${customHeader}\n`);

    res.send('Data logged successfully');
});

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});